client/src/pages/home.tsx.content:
import { useState, useEffect, useRef } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Search, MessageSquare, BarChart3, Info } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { CompanySelectionModal, type ApolloOrganization } from "@/components/ui/company-selection-modal";
import { UserDropdown } from "@/components/ui/user-dropdown";

export default function Home() {
  const [inputType, setInputType] = useState<"text" | "url">("url");
  const [jobInput, setJobInput] = useState("");
  const [, setLocation] = useLocation();
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [autoSwitchMessage, setAutoSwitchMessage] = useState("");
  const [unsupportedUrlError, setUnsupportedUrlError] = useState("");
  const [isButtonDisabled, setIsButtonDisabled] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Company search flow state
  const [showCompanyModal, setShowCompanyModal] = useState(false);
  const [pendingJobContent, setPendingJobContent] = useState("");
  const [organizations, setOrganizations] = useState<ApolloOrganization[]>([]);
  const [selectedOrganizationId, setSelectedOrganizationId] = useState<string | null>(null);
  const [customDomain, setCustomDomain] = useState<string>("");

  // Auto-focus when switching to text input after URL failure
  useEffect(() => {
    if (inputType === "text" && textareaRef.current) {
      textareaRef.current.focus();
    }
  }, [inputType]);

  // Company search mutation
  const companySearchMutation = useMutation({
    mutationFn: async (jobContent: string) => {
      const response = await apiRequest("POST", "/api/company/search", { jobContent });
      return response.json();
    },
    onError: (error) => {
      toast({
        title: "Company Search Failed",
        description: error.message || "Failed to search for company information",
        variant: "destructive",
      });
    },
  });

  const submitMutation = useMutation({
    mutationFn: async (data: { 
      jobInput: string; 
      inputType: string; 
      organizationId?: string;
      companyDomain?: string;
    }) => {
      // Generate a unique runId for this submission
      const runId = `run_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      const response = await apiRequest("POST", "/api/submissions", { ...data, runId });
      return response.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["/api/submissions"] });
      setLocation(`/results/${data.id}`);

      // Reset modal state
      setShowCompanyModal(false);
      setPendingJobContent("");
      setOrganizations([]);
      setSelectedOrganizationId(null);
      setCustomDomain("");
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to process job submission",
        variant: "destructive",
      });
    },
  });

  // Smart content detection
  const unsupportedDomains = ["linkedin.com", "wellfound.com"];

  const isValidUrl = (text: string): boolean => {
    try {
      const url = new URL(text);
      return url.protocol === 'http:' || url.protocol === 'https:';
    } catch {
      return false;
    }
  };

  const isUnsupportedDomain = (text: string): boolean => {
    try {
      const url = new URL(text);
      return unsupportedDomains.some(domain => url.hostname.includes(domain));
    } catch {
      return false;
    }
  };

  const looksLikeJobDescription = (text: string): boolean => {
    const lowercaseText = text.toLowerCase();
    const jobDescriptorWords = [
      'responsibilities', 'requirements', 'qualifications', 'experience',
      'we are looking', 'job description', 'role summary', 'about the role',
      'what you\'ll do', 'who you are', 'benefits', 'salary', 'location'
    ];

    return jobDescriptorWords.some(word => lowercaseText.includes(word)) && 
           text.length > 100; // Job descriptions are typically longer
  };

  const handleInputChange = (value: string) => {
    setJobInput(value);
    setAutoSwitchMessage("");
    setUnsupportedUrlError("");
    setIsButtonDisabled(false);

    if (inputType === "url" && value.trim()) {
      // Check for unsupported domains first
      if (isValidUrl(value) && isUnsupportedDomain(value)) {
        setUnsupportedUrlError("This URL is not supported. Please paste the full job description instead.");
        setIsButtonDisabled(true);
        return;
      }

      // Smart auto-switching logic for job descriptions in URL field
      if (value.length > 50 && !isValidUrl(value) && looksLikeJobDescription(value)) {
        setAutoSwitchMessage("This looks like a full job description. Switching to the right input field…");
        setTimeout(() => {
          setInputType("text");
          setAutoSwitchMessage("");
        }, 1500);
      }
    }
  };

  const handleSubmit = async () => {
    if (!jobInput.trim()) {
      toast({
        title: "Error",
        description: "Please enter a job description or URL",
        variant: "destructive",
      });
      return;
    }

    // For URL submissions, try to validate and handle failures
    if (inputType === "url") {
      if (!isValidUrl(jobInput.trim())) {
        toast({
          title: "Invalid URL",
          description: "Please enter a valid URL (e.g., https://company.com/jobs/position)",
          variant: "destructive",
        });
        return;
      }
    }

    try {
      // Step 1: Search for company information first
      setPendingJobContent(jobInput.trim());
      const companySearchResult = await companySearchMutation.mutateAsync(jobInput.trim());

      if (companySearchResult.organizations && companySearchResult.organizations.length > 0) {
        // Show company selection modal if multiple matches found
        setOrganizations(companySearchResult.organizations);
        setShowCompanyModal(true);
      } else {
        // No company matches found, proceed with standard submission
        await submitMutation.mutateAsync({ 
          jobInput: jobInput.trim(), 
          inputType 
        });
      }
    } catch (error: any) {
      // Handle URL parsing failures with auto-switch
      if (inputType === "url" && (
        error.message?.includes("fetch") || 
        error.message?.includes("parse") ||
        error.message?.includes("timeout") ||
        error.message?.includes("empty")
      )) {
        toast({
          title: "URL Parsing Failed",
          description: "We couldn't fetch the job details from that URL. Please paste the job description manually.",
          variant: "destructive",
        });
        setInputType("text");
        // Focus will be handled by useEffect below
        return;
      }

      // Re-throw other errors to be handled by mutation's onError
      throw error;
    }
  };

  const handleCompanyConfirm = async (organizationId: string | null, customDomain?: string) => {
    try {
      await submitMutation.mutateAsync({ 
        jobInput: pendingJobContent, 
        inputType,
        organizationId: organizationId || undefined,
        companyDomain: customDomain || undefined
      });
    } catch (error) {
      // Error will be handled by mutation's onError
    }
  };

  const handleLogout = () => {
    window.location.href = "/api/logout";
  };

  const goToDashboard = () => {
    setLocation("/dashboard");
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <h1 className="text-xl font-bold text-slate-900">Recruiter Contact Finder</h1>
            </div>
            <div className="flex items-center">
              <UserDropdown 
                user={user}
                onLogout={handleLogout}
                onDashboard={goToDashboard}
                showDashboard={true}
              />
            </div>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 pt-16 pb-24">
        <div className="text-center">
          <h1 className="text-4xl sm:text-5xl font-bold text-slate-900 mb-6">
            Find the right recruiter for any job instantly.
          </h1>
          <p className="text-xl text-slate-600 mb-12 max-w-2xl mx-auto">
            Paste a job description or URL and get recruiter contacts with personalized outreach messages powered by AI.
          </p>
        </div>

        {/* Input Form */}
        <Card className="shadow-sm border border-slate-200">
          <CardContent className="p-8">
            <div className="space-y-6">
              {/* Toggle Buttons */}
              <div className="flex bg-slate-100 p-1 rounded-lg w-fit mx-auto">
                <Button
                  variant={inputType === "url" ? "default" : "ghost"}
                  size="sm"
                  onClick={() => {
                    setInputType("url");
                    setAutoSwitchMessage("");
                    setUnsupportedUrlError("");
                    setIsButtonDisabled(false);
                  }}
                  className={inputType === "url" ? "bg-white text-slate-900 shadow-sm" : "text-slate-600"}
                >
                  Job URL
                </Button>
                <Button
                  variant={inputType === "text" ? "default" : "ghost"}
                  size="sm"
                  onClick={() => {
                    setInputType("text");
                    setAutoSwitchMessage("");
                    setUnsupportedUrlError("");
                    setIsButtonDisabled(false);
                  }}
                  className={inputType === "text" ? "bg-white text-slate-900 shadow-sm" : "text-slate-600"}
                >
                  Job Description
                </Button>
              </div>

              {/* Auto-switch message */}
              {autoSwitchMessage && (
                <Alert className="bg-blue-50 border-blue-200">
                  <Info className="h-4 w-4 text-blue-600" />
                  <AlertDescription className="text-blue-800">
                    {autoSwitchMessage}
                  </AlertDescription>
                </Alert>
              )}

              {/* Input Area with Loading State */}
              {submitMutation.isPending ? (
                <div className="flex flex-col items-center justify-center h-48 space-y-4">
                  {/* Loading Spinner */}
                  <div className="w-12 h-12 border-4 border-slate-200 border-t-blue-600 rounded-full animate-spin"></div>
                  {/* Processing Text */}
                  <p className="text-sm text-slate-500 animate-pulse">
                    {inputType === "url" ? "Analyzing job URL..." : "Processing job description..."}
                  </p>
                </div>
              ) : (
                <>
                  {inputType === "url" ? (
                    <div>
                      <label className="block text-sm font-medium text-slate-700 mb-2">
                        Job URL
                      </label>
                      <Input
                        ref={inputRef}
                        type="url"
                        placeholder="Paste the job listing URL (e.g., Greenhouse, Lever, company career pages)"
                        value={jobInput}
                        onChange={(e) => handleInputChange(e.target.value)}
                        className={`text-base ${unsupportedUrlError ? 'border-red-300 focus:border-red-500' : ''}`}
                      />
                      {unsupportedUrlError ? (
                        <p className="text-sm text-red-600 mt-2">
                          {unsupportedUrlError}
                        </p>
                      ) : (
                        <p className="text-xs text-slate-500 mt-1">
                          We'll automatically fetch and analyze the job details from the URL
                        </p>
                      )}
                    </div>
                  ) : (
                    <div>
                      <label className="block text-sm font-medium text-slate-700 mb-2">
                        Job Description
                      </label>
                      <Textarea
                        ref={textareaRef}
                        placeholder="Paste the full job description here..."
                        className="h-48 resize-none text-base"
                        value={jobInput}
                        onChange={(e) => handleInputChange(e.target.value)}
                      />
                      <p className="text-xs text-slate-500 mt-1">
                        Include as much detail as possible for better recruiter matching
                      </p>
                    </div>
                  )}
                </>
              )}

              {/* Submit Button - Hidden during loading */}
              {!submitMutation.isPending && (
                <div className="text-center">
                  <div className="relative group">
                    <Button 
                      onClick={handleSubmit}
                      className="bg-primary text-white hover:bg-blue-700 px-8 py-3 disabled:opacity-50 disabled:cursor-not-allowed"
                      size="lg"
                      disabled={!jobInput.trim() || isButtonDisabled}
                    >
                      {inputType === "url" ? "Analyze Job & Find Recruiters" : "Find Recruiters & Generate Messages"}
                      <svg className="w-5 h-5 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path>
                      </svg>
                    </Button>
                    {isButtonDisabled && (
                      <div className="absolute -top-10 left-1/2 transform -translate-x-1/2 bg-slate-900 text-white text-xs rounded px-2 py-1 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
                        Unsupported link. Paste full job description instead.
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </CardContent>
        </Card>



        {/* Features Grid */}
        <div className="grid md:grid-cols-3 gap-8 mt-20">
          <div className="text-center">
            <div className="bg-blue-100 w-12 h-12 rounded-lg flex items-center justify-center mx-auto mb-4">
              <Search className="w-6 h-6 text-primary" />
            </div>
            <h3 className="text-lg font-semibold text-slate-900 mb-2">AI-Powered Search</h3>
            <p className="text-slate-600">Advanced AI extracts recruiter information and contact details from job postings.</p>
          </div>
          <div className="text-center">
            <div className="bg-emerald-100 w-12 h-12 rounded-lg flex items-center justify-center mx-auto mb-4">
              <MessageSquare className="w-6 h-6 text-emerald-600" />
            </div>
            <h3 className="text-lg font-semibold text-slate-900 mb-2">Personalized Messages</h3>
            <p className="text-slate-600">Get tailored email and LinkedIn messages for effective outreach.</p>
          </div>
          <div className="text-center">
            <div className="bg-amber-100 w-12 h-12 rounded-lg flex items-center justify-center mx-auto mb-4">
              <BarChart3 className="w-6 h-6 text-amber-600" />
            </div>
            <h3 className="text-lg font-semibold text-slate-900 mb-2">Track History</h3>
            <p className="text-slate-600">Keep track of all your searches and generated messages in your dashboard.</p>
          </div>
        </div>
      </div>

      {/* Company Selection Modal */}
      <CompanySelectionModal
        isOpen={showCompanyModal}
        onClose={() => {
          setShowCompanyModal(false);
          setPendingJobContent("");
          setOrganizations([]);
        }}
        organizations={organizations}
        onConfirm={handleCompanyConfirm}
        isLoading={submitMutation.isPending}
      />
    </div>
  );
}

client/src/pages/results.tsx.content:
import { useEffect, useState } from "react";
import { useParams, useLocation } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { ArrowLeft, ExternalLink, ChevronDown, ChevronUp } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { JobDetailCard } from "@/components/ui/job-detail-card";
import { UserDropdown } from "@/components/ui/user-dropdown";
import ContactCards from "@/components/ui/contact-cards";
import type { JobSubmissionWithRecruiters } from "@shared/schema";

export default function Results() {
  const params = useParams();
  const [, setLocation] = useLocation();
  const { user, isAuthenticated, isLoading } = useAuth();
  const { toast } = useToast();
  const submissionId = params.id;

  // State for UI interactions
  const [jobSummaryExpanded, setJobSummaryExpanded] = useState(true);

  const handleLogout = () => {
    window.location.href = "/api/logout";
  };

  const handleBackToDashboard = () => {
    setLocation("/dashboard");
  };

  // Fetch submission data
  const {
    data: submission,
    isLoading: submissionLoading,
    error,
  } = useQuery<JobSubmissionWithRecruiters>({
    queryKey: [`/api/submissions/${submissionId}`],
    enabled: !!submissionId && isAuthenticated,
    retry: (failureCount, error) => {
      if (isUnauthorizedError(error as Error)) return false;
      return failureCount < 3;
    },
  });

  // Fetch enhanced job data with standardized format
  const { data: enhancedJobData } = useQuery<{
    submissionId: number;
    enhancedData?: {
      job_title?: string;
      company_name?: string;
      job_url?: string;
      company_website?: string;
      location?: string;
      job_description?: string;
      key_responsibilities?: string[];
      requirements?: string[];
      likely_departments?: string[];
      linkedin_keywords?: string[];
    };
    hasEnhancedData: boolean;
  }>({
    queryKey: [`/api/submissions/${submissionId}/job-data`],
    enabled: !!submissionId && isAuthenticated,
    retry: (failureCount, error) => {
      if (isUnauthorizedError(error as Error)) return false;
      return failureCount < 3;
    },
  });

  // Redirect to login if not authenticated
  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, toast]);

  if (isLoading || submissionLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
          <p className="text-slate-600">Loading submission details...</p>
        </div>
      </div>
    );
  }

  if (error || !submission) {
    return (
      <div className="min-h-screen bg-slate-50">
        <nav className="bg-white border-b border-slate-200">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-16">
              <h1 className="text-xl font-bold text-slate-900">Recruiter Contact Finder</h1>
              <UserDropdown 
                user={user}
                onLogout={handleLogout}
                onDashboard={handleBackToDashboard}
                showDashboard={true}
              />
            </div>
          </div>
        </nav>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          <div className="text-center">
            <h2 className="text-2xl font-bold text-slate-900 mb-4">Submission Not Found</h2>
            <p className="text-slate-600 mb-6">The submission you're looking for doesn't exist or you don't have access to it.</p>
            <Button onClick={handleBackToDashboard} className="bg-primary text-white hover:bg-blue-700">
              Back to Dashboard
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <h1 className="text-xl font-bold text-slate-900">Recruiter Contact Finder</h1>
            <UserDropdown 
              user={user}
              onLogout={handleLogout}
              onDashboard={handleBackToDashboard}
              showDashboard={true}
            />
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <Button
            variant="ghost"
            onClick={handleBackToDashboard}
            className="text-primary hover:text-blue-700 mb-4 p-0"
          >
            <ArrowLeft className="w-4 h-4 mr-1" />
            Back to Dashboard
          </Button>
          <h1 className="text-2xl font-bold text-slate-900 mb-2">
            {submission.jobTitle || "Untitled Position"}
          </h1>
          <p className="text-slate-600">
            {submission.companyName || "Unknown Company"}
          </p>
          {enhancedJobData?.enhancedData?.location && (
            <p className="text-sm text-slate-500 mt-1">
              📍 {enhancedJobData?.enhancedData?.location}
            </p>
          )}
        </div>

        {/* Enhanced Job Information Display */}
        {enhancedJobData?.hasEnhancedData && enhancedJobData.enhancedData ? (
          <JobDetailCard 
            jobData={{
              job_title: enhancedJobData.enhancedData.job_title || "Not specified",
              company_name: enhancedJobData.enhancedData.company_name || "Not specified",
              job_url: enhancedJobData.enhancedData.job_url || (submission.inputType === "url" ? submission.jobInput : "Not specified"),
              company_website: enhancedJobData.enhancedData.company_website || "Not specified",
              location: enhancedJobData.enhancedData.location || "Not specified",
              job_description: enhancedJobData.enhancedData.job_description || "Not specified",
              key_responsibilities: enhancedJobData.enhancedData.key_responsibilities || ["Not specified"],
              requirements: enhancedJobData.enhancedData.requirements || ["Not specified"],
              likely_departments: enhancedJobData.enhancedData.likely_departments || ["Other"],
            }}
            className="mb-8"
          />
        ) : (
          /* Fallback job info if no enhanced data */
          <Collapsible open={jobSummaryExpanded} onOpenChange={setJobSummaryExpanded} className="mb-8">
            <Card>
              <CardContent className="p-6">
                <CollapsibleTrigger className="flex items-center justify-between w-full text-left">
                  <h2 className="text-lg font-semibold text-slate-900">Job Information</h2>
                  {jobSummaryExpanded ? (
                    <ChevronUp className="w-5 h-5 text-slate-500" />
                  ) : (
                    <ChevronDown className="w-5 h-5 text-slate-500" />
                  )}
                </CollapsibleTrigger>

                <CollapsibleContent className="mt-4 space-y-4">
                  {/* Job URL - Display first */}
                  {submission?.inputType === "url" && (
                    <div>
                      <h3 className="font-medium text-slate-900 mb-2">Job URL</h3>
                      <a 
                        href={submission.jobInput} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-primary hover:text-blue-700 break-all text-sm flex items-center"
                      >
                        {submission.jobInput}
                        <ExternalLink className="w-4 h-4 ml-2 flex-shrink-0" />
                      </a>
                    </div>
                  )}

                  {/* Job Description Summary - Display second */}
                  {submission?.inputType === "text" && (
                    <div>
                      <h3 className="font-medium text-slate-900 mb-2">Job Description</h3>
                      <p className="text-slate-700 text-sm leading-relaxed">
                        {submission.jobInput && submission.jobInput.length > 500 
                          ? `${submission.jobInput.substring(0, 500)}...`
                          : submission.jobInput
                        }
                      </p>
                    </div>
                  )}
                </CollapsibleContent>
              </CardContent>
            </Card>
          </Collapsible>
        )}

        {/* Contact Cards */}
        {submission.recruiters && submission.recruiters.length > 0 ? (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold text-slate-900">Recruiter Contacts</h2>
              <Badge variant="outline" className="bg-blue-50 text-blue-700 border-blue-200">
                {submission.recruiters.length} contacts found
              </Badge>
            </div>
            <ContactCards 
              contacts={submission.recruiters.map(r => ({
                id: r.id,
                name: r.name || "Unknown",
                title: r.title || "Unknown Title",
                email: r.email || "",
                linkedinUrl: r.linkedinUrl || undefined,
                confidence: r.confidenceScore || 0,
                department: (r as any).outreachBucket === "recruiter" ? "Recruiting" : 
                           (r as any).department || "Other",
                emailVerified: (r as any).emailVerified || false,
                verificationStatus: (r as any).verificationStatus || "unknown",
                sourcePlatform: r.sourcePlatform || "openai",
                apolloId: (r as any).apolloId,
                isRecruiterRole: (r as any).outreachBucket === "recruiter" || 
                               (r.title?.toLowerCase().includes("recruiter") || false),
                contactStatus: (r as any).contactStatus,
                notes: (r as any).notes,
                lastContacted: (r as any).lastContacted,
                influenceScore: (r as any).influenceScore,
                emailDraft: (r as any).emailDraft,
                linkedinMessage: (r as any).linkedinMessage,
              }))}
              submissionId={parseInt(submissionId || "0")}
            />
          </div>
        ) : (
          <div className="text-center py-12">
            <h3 className="text-lg font-semibold text-slate-900 mb-2">No Contacts Found</h3>
            <p className="text-slate-600 mb-4">
              We couldn't find any recruiter contacts for this position yet.
            </p>
            <Button
              onClick={() => setLocation("/")}
              className="bg-primary text-white hover:bg-blue-700"
            >
              Try Another Search
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

