                              <div className="space-y-3">
                                {recruiter.email && (
                                  <div className="flex items-center space-x-3">
                                    <Mail className="w-5 h-5 text-slate-400" />
                                    <span className="text-slate-700">{recruiter.email}</span>
                                    <Button
                                      variant="ghost"
