                      {job.status}
                      <ChevronDown className="w-3.5 h-3.5 ml-1" />
                    </button>

                    {openStatusDropdown === job.id && (
                      <div className="absolute top-full mt-1 right-0 bg-white rounded-lg shadow-lg border border-[#E2E8F0] py-1 z-10 min-w-[160px]">
