                  ></div>
                </div>

                {/* Additional Info */}
                <div className="space-y-2">
                  <p className="text-[#718096] text-sm">{credit.renewalText}</p>
                  {credit.note && (
                    <p className="text-[#718096] text-sm font-medium">{credit.note}</p>
