                      />
                    ) : (
                      <div className="bg-slate-50 p-4 rounded-lg">
                        <div className="text-sm text-slate-700 whitespace-pre-line">
                          {linkedinContent}
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>
          )}
        </CollapsibleContent>
      </div>
    </Collapsible>
  );
}

