backend/middleware/sessionAuth.ts.content:
import { Request, Response, NextFunction } from "express";
import { supabaseAdmin } from "../lib/supabaseClient";

declare global {
  namespace Express {
    interface Request {
      user?: {
        id: string;
      } | null;
    }
  }
}

export async function sessionAuth(
  req: Request,
  res: Response,
  next: NextFunction
) {
  try {
    const sessionId = req.cookies.session_id;

    if (!sessionId) {
      req.user = null;
      return next();
    }

    const { data: session, error } = await supabaseAdmin
      .from("sessions")
      .select("user_id")
      .eq("id", sessionId)
      .single();

    if (error || !session) {
      req.user = null;
      return next();
    }

    req.user = { id: session.user_id };
    return next();
  } catch (error) {
    console.error("Session auth error:", error);
    req.user = null;
    return next();
  }
}

